<?php include '_header.php'; if($_SERVER['REQUEST_METHOD']==='POST'){csrf_verify(); if(isset($_POST['delete'])){db()->prepare('DELETE FROM categories WHERE id=?')->execute([(int)$_POST['delete']]);} else { $slug=strtolower(trim(preg_replace('/[^a-z0-9]+/','-',$_POST['name']),'-')); if($_POST['id']) db()->prepare('UPDATE categories SET name=?,slug=?,description=? WHERE id=?')->execute([$_POST['name'],$slug,$_POST['description'],$_POST['id']]); else db()->prepare('INSERT INTO categories(name,slug,description) VALUES(?,?,?)')->execute([$_POST['name'],$slug,$_POST['description']]);} redirect('categories.php');} $rows=db()->query('SELECT * FROM categories ORDER BY id DESC')->fetchAll(); ?>
<h1>CRUD Kategori</h1><form method="post" class="row g-2 mb-4"><input type="hidden" name="_csrf" value="<?=csrf_token()?>"><input type="hidden" name="id" id="id"><div class="col-md-4"><input class="form-control" name="name" id="name" placeholder="Nama kategori" required></div><div class="col-md-5"><input class="form-control" name="description" id="description" placeholder="Deskripsi"></div><div class="col"><button class="btn btn-light">Simpan</button></div></form><table class="table table-dark"><tr><th>Nama</th><th>Deskripsi</th><th></th></tr><?php foreach($rows as $r):?><tr><td><?=e($r['name'])?></td><td><?=e($r['description'])?></td><td><button class="btn btn-sm btn-warning" onclick='id.value="<?=$r['id']?>";name.value=<?=json_encode($r['name'])?>;description.value=<?=json_encode($r['description'])?>'>Edit</button> <form class="d-inline" method="post"><input type="hidden" name="_csrf" value="<?=csrf_token()?>"><button class="btn btn-sm btn-danger" name="delete" value="<?=$r['id']?>">Hapus</button></form></td></tr><?php endforeach;?></table><?php include '_footer.php'; ?>
